#include <OneWire.h>
#include <DallasTemperature.h>
#include <SPI.h>
#include <LoRa.h>
#include <SD.h>
#define GA A0
#define GB A1
#define GC A2
#define BUZZER 8
#define LED 9
#define SD_CS 10
#define ONE_WIRE_BUS 2
#define SPAN_AB 4500.0f
#define SPAN_BC 4500.0f
#define LIMIT_1_500 0.002f
#define LIMIT_1_300 0.00333f
#define GAUGE_RANGE 100.0f
OneWire ow(ONE_WIRE_BUS); DallasTemperature ds(&ow);
float zero[3]={0,0,0};

float angular_distortion(float d,float span){return span>0?d/span:0;}

float read_settlement(int pin){return (analogRead(pin)/1023.0f)*GAUGE_RANGE;}

void check_distortion(float*s){
  float dAB=fabs(s[0]-s[1]),dBC=fabs(s[1]-s[2]);
  float tAB=angular_distortion(dAB,SPAN_AB);
  float tBC=angular_distortion(dBC,SPAN_BC);
  float worst=max(tAB,tBC);
  if(worst>LIMIT_1_300){tone(BUZZER,2000);analogWrite(LED,255);}
  else if(worst>LIMIT_1_500){tone(BUZZER,1000);analogWrite(LED,128);}
  else{noTone(BUZZER);analogWrite(LED,(int)(worst/LIMIT_1_500*100));}
}

void send_lora(float*s,float tAB,float tBC){
  LoRa.beginPacket();
  for(int i=0;i<3;i++){LoRa.print(s[i]);LoRa.print(',');}
  LoRa.print(tAB);LoRa.print(',');LoRa.print(tBC);
  LoRa.endPacket();
}

void log_sd(float*s,float T){
  File f=SD.open("settle.csv",FILE_WRITE);
  if(f){f.print(millis());f.print(',');f.print(T);for(int i=0;i<3;i++){f.print(',');f.print(s[i]);}f.println();f.close();}
}

void setup(){
  Serial.begin(115200);ds.begin();SD.begin(SD_CS);LoRa.begin(915E6);
  pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);
  for(int i=0;i<3;i++) zero[i]=read_settlement(GA+i);
}

void loop(){
  float s[3];
  ds.requestTemperatures();
  float T=ds.getTempCByIndex(0);
  float tc=(T-20.0f)*0.01f;
  for(int i=0;i<3;i++) s[i]=read_settlement(GA+i)-zero[i]-tc;
  float tAB=angular_distortion(fabs(s[0]-s[1]),SPAN_AB);
  float tBC=angular_distortion(fabs(s[1]-s[2]),SPAN_BC);
  check_distortion(s);
  log_sd(s,T);
  static unsigned long lastLora=0;
  if(millis()-lastLora>86400000UL){send_lora(s,tAB,tBC);lastLora=millis();}
  Serial.print("s0=");Serial.print(s[0]);Serial.print(" tAB=");Serial.println(tAB);
  delay(1800000);
}
